import torch
import torchvision
from PIL import Image
import requests
import io


class Model(torch.nn.Module):
    def __init__(self, model):
        super().__init__()

        self.model = model

    def forward(self, x):
        return self.model(x)


def get_prediction(image):
    device = torch.device('cuda' if torch.cuda.is_available() else 'cpu')
    model = Model(torchvision.models.resnet18())
    model.load_state_dict(torch.load('resnet18-5c106cde.pth'))

    model.eval().to(device)

    image = Image.open(io.BytesIO(image))
    image = torchvision.transforms.functional.resize(
        image, (224, 224), interpolation=Image.BILINEAR)
    image = torchvision.transforms.functional.to_tensor(image).unsqueeze(0)

    with torch.no_grad():
        output = model(image.to(device))

        _, predicted = torch.max(output.data, 1)
        return predicted


def main():
    url = 'http://localhost:8000/'
    image = requests.get('https://i.imgur.com/7v3y9oV.jpg').content

    response = requests.post(url, data=image).json()
    print(response)


if __name__ == '__main__':
    main()